using System.Text.Json;
using System.Text.Json.Serialization;
using System.Text.Json.Serialization.Metadata;

// Options with the default reflection-based resolver
var options = new JsonSerializerOptions(JsonSerializerDefaults.Web);

// --- 1. GetTypeInfo<T>(): strongly-typed metadata retrieval ---
JsonTypeInfo<Person> personInfo = options.GetTypeInfo<Person>();
Console.WriteLine($"GetTypeInfo<Person> → Type = {personInfo.Type.Name}");

string json = JsonSerializer.Serialize(new Person("Ada", 37), personInfo);
Console.WriteLine($"Serialized: {json}");

// --- 2. TryGetTypeInfo<T>(): probe without throwing ---

// 2a. Type the resolver CAN handle (Person)
if (options.TryGetTypeInfo<Person>(out JsonTypeInfo<Person>? found))
    Console.WriteLine($"TryGetTypeInfo<Person> → found, Type = {found!.Type.Name}");
else
    Console.WriteLine("TryGetTypeInfo<Person> → not available");

// 2b. Type the resolver CANNOT handle
// A source-gen-only options instance has no resolver for Widget.
var limited = new JsonSerializerOptions { TypeInfoResolver = new LimitedResolver() };

if (limited.TryGetTypeInfo<Widget>(out JsonTypeInfo<Widget>? widgetInfo))
    Console.WriteLine($"TryGetTypeInfo<Widget> → found, Type = {widgetInfo!.Type.Name}");
else
    Console.WriteLine("TryGetTypeInfo<Widget> → not available (no throw!)");

// --- types ---
public record Person(string Name, int Age);
public record Widget(int Id, string Label);

// A resolver that resolves nothing, simulating a limited source-gen context.
file class LimitedResolver : IJsonTypeInfoResolver
{
    public JsonTypeInfo? GetTypeInfo(Type type, JsonSerializerOptions options) => null;
}

